SELECT id, user_id, username, module, operation, request_url, request_method, method, params, result, duration, ip, created_at
FROM sys_operation_log


        AND created_at >= #{startTime}


        AND created_at <= #{endTime}


ORDER BY created_at DESC
LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*)
FROM sys_operation_log


        AND created_at >= #{startTime}


        AND created_at <= #{endTime}
